SELECT ?homeTeam ?homeTeamLabel WHERE {
  ?match wdt:P179 wd:Q16151453 ;
         wdt:P1545 "Third Round" ;
         wdt:P1314 ?score ;
         wdt:P1416 ?homeTeam .
  FILTER(regex(STR(?score), '^([0-9]+)-\1$'))
  ?homeTeam rdfs:label ?homeTeamLabel .
  FILTER(LANG(?homeTeamLabel) = "ga")
} LIMIT 1

